=mutation ($cardId: ID!, $toAdd: [UndefinedInput!]!) {
  updateFieldsValues(
    input: {
      nodeId: $cardId
      values: [
        {
          fieldId: "cards_de_csat_e_nps"
          value: $toAdd
          operation: ADD
        }
      ]
    }
  ) {
    success
    userErrors { field message }
    updatedNode {
      ... on Card { id }
    }
  }
}

